sql:
SELECT o.outlet_id, o.location_type, s.total_sales
FROM outlets o
INNER JOIN sales_by_outlet s ON o.outlet_id = s.outlet_id;

SELECT total_sales 
FROM sales_by_outlet 
WHERE outlet_id = '0';

SELECT * FROM items
WHERE item_type = 'Dairy' AND fat_content = 1 AND visibility > 0.015
ORDER BY item_mrp DESC;

SELECT * 
FROM items
WHERE item_id IN (
  SELECT item_id 
  FROM sales_by_item
  WHERE sales_count > (
    SELECT AVG(sales_count) 
    FROM sales_by_item
  )
);

external_knowledge:
- "treasures" metaphorically refers to sales amounts representing valuable data;
- "origins" refers to the unique identifiers (item_id and outlet_id) that trace the source of sales data;
- "market's jewelry box" is a metaphor for the sales data repository;
- "intricate designs of their craftsmanship" symbolizes the items table, which provides details about the items associated with the sales;
- "paths of the marketplaces" is a metaphor for the outlets table, indicating the sales locations.

- "massive treasures" refers to the heaviest items in terms of weight;
- "kingdom of supermarkets" refers to outlets categorized as supermarkets;
- "surpassed the threshold of a hundred sales transactions" refers to items with a sales count greater than 100;
- "stand out as the heaviest in weight" means selecting the top three by weight.

sql:
SELECT item_id, visibility_score
FROM visibility_data
WHERE visibility_score > (SELECT AVG(visibility_score) FROM visibility_data);

SELECT item_description, item_image 
FROM items 
WHERE item_id = '1';

SELECT outlet_id, total_sales, sales_count
FROM sales_by_outlet
WHERE total_sales > 50000 AND sales_count > 300;

SELECT outlet_id, item_id, MAX(visibility_score) AS MaxVisibility
FROM visibility_data
GROUP BY outlet_id, item_id;

SELECT DISTINCT users.username
FROM users
JOIN sales_sessions ON users.user_id = sales_sessions.user_id;

SELECT item_id, COUNT(sales_id) as sales_count
FROM sales
GROUP BY item_id;

SELECT sales_count
FROM sales_by_item
WHERE item_id = '1';

SELECT * 
FROM sales_sessions
WHERE user_id = 'user_id_value';

SELECT AVG(visibility_score) AS avg_visibility
FROM visibility_data
WHERE outlet_id = '1';
